242→                />
243→            </div>
244→
245→            {/* Comment Panel */}
246→            <AnimatePresence>
247→                {activeComment && (
248→                    <CommentPanel
249→                        chapterId={chapterId}
250→                        activeComment={activeComment}
251→                        onClose={() => setActiveComment(null)}
252→                    />
253→                )}
254→            </AnimatePresence>
255→
256→            {/* Navigation */}
257→            <div className="chapter-reader-nav">
258→                {prevCh ? (
259→                    <button
260→                        className="chapter-nav-btn chapter-nav-prev"
261→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
262→                    >
263→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
264→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
265→                        </svg>
266→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
267→                    </button>
268→                ) : <div />}
269→                {nextCh ? (
270→                    <button
271→                        className="chapter-nav-btn chapter-nav-next"
272→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
273→                    >
274→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
275→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
276→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
277→                        </svg>
278→                    </button>
279→                ) : <div />}
280→            </div>
281→        </motion.div>
282→        </>
283→    );
