 18→// ── Vote toggle ──
 19→export const toggleVoteService = async (storyId, userId) => {
 20→    if (!storyId || !userId) {
 21→        throw { status: 400, error: 'storyId and userId are required' };
 22→    }
 23→
 24→    const { data: existing } = await supabase
 25→        .from('story_votes')
 26→        .select('id')
 27→        .eq('story_id', storyId)
 28→        .eq('user_id', userId)
 29→        .maybeSingle();
 30→
 31→    if (!existing) {
 32→        const { error } = await supabase
 33→            .from('story_votes')
 34→            .insert({ story_id: storyId, user_id: userId });
 35→
 36→        if (error) {
 37→            console.error('supabase error inserting vote:', error.message);
 38→            throw { status: 500, error: 'failed to vote' };
 39→        }
 40→
 41→        // Increment vote_count
 42→        const { data: story } = await supabase
 43→            .from('stories')
 44→            .select('vote_count')
 45→            .eq('id', storyId)
 46→            .single();
 47→        if (story) {
 48→            await supabase
 49→                .from('stories')
 50→                .update({ vote_count: (story.vote_count || 0) + 1 })
 51→                .eq('id', storyId);
 52→        }
 53→
 54→        return { message: 'voted' };
 55→    } else {
 56→        const { error } = await supabase
 57→            .from('story_votes')
 58→            .delete()
 59→            .eq('story_id', storyId)
 60→            .eq('user_id', userId);
 61→
 62→        if (error) {
 63→            console.error('supabase error deleting vote:', error.message);
 64→            throw { status: 500, error: 'failed to unvote' };
 65→        }
 66→
 67→        // Decrement vote_count
 68→        const { data: story } = await supabase
 69→            .from('stories')
 70→            .select('vote_count')
 71→            .eq('id', storyId)
 72→            .single();
 73→        if (story) {
 74→            await supabase
 75→                .from('stories')
 76→                .update({ vote_count: Math.max(0, (story.vote_count || 0) - 1) })
 77→                .eq('id', storyId);
 78→        }
 79→
 80→        return { message: 'unvoted' };
 81→    }
 82→};
