311→    if (!storyId || !userId || !chapterId) {
312→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
313→    }
314→
315→    // Check if this is a new reader (no existing progress for this user+story)
316→    const { data: existing } = await supabase
317→        .from('reading_progress')
318→        .select('id')
319→        .eq('user_id', userId)
320→        .eq('story_id', storyId)
321→        .maybeSingle();
