327→            story_id: storyId,
328→            chapter_id: chapterId,
329→            scroll_position: scrollPosition || 0,
330→            last_read_at: new Date().toISOString(),
331→        }, { onConflict: 'user_id,story_id' })
332→        .select('*')
333→        .single();
334→
335→    if (error) {
336→        console.error('supabase error saving progress:', error.message);
337→        throw { status: 500, error: 'failed to save progress' };
338→    }
339→
340→    // Increment read_count if this is a new reader (skip if author)
