 1→import { useQuery, useInfiniteQuery } from '@tanstack/react-query';
 2→import { getMyStories, getMyLibrary, getStoryById, getChapter, getChapterComments, getChapterCommentCounts, getUserStories } from '../../../../API/StoryApi';
 3→
 4→export const useMyStories = (token) => {
 5→    return useInfiniteQuery({
 6→        queryKey: ['myStories'],
 7→        queryFn: ({ pageParam }) => getMyStories(token, 5, pageParam),
 8→        initialPageParam: undefined,
 9→        getNextPageParam: (lastPage) => {
10→            if (lastPage.hasMore) {
11→                const lastStory = lastPage.data[lastPage.data.length - 1];
12→                return new Date(lastStory.updated_at).toISOString();
13→            }
14→            return undefined;
15→        },
16→        enabled: !!token,
17→        staleTime: 1000 * 60 * 5,
18→        refetchOnWindowFocus: false,
19→    });
20→};
21→
22→export const useMyLibrary = (token) => {
23→    return useInfiniteQuery({
24→        queryKey: ['myLibrary'],
25→        queryFn: ({ pageParam }) => getMyLibrary(token, 5, pageParam),
26→        initialPageParam: undefined,
27→        getNextPageParam: (lastPage) => {
28→            if (lastPage.hasMore) {
29→                const lastStory = lastPage.data[lastPage.data.length - 1];
30→                return new Date(lastStory.added_at).toISOString();
31→            }
32→            return undefined;
33→        },
34→        enabled: !!token,
35→        staleTime: 1000 * 60 * 5,
36→        refetchOnWindowFocus: false,
37→    });
38→};
