50→export const useChapter = (storyId, chapterId, token) => {
51→    return useQuery({
52→        queryKey: ['chapter', storyId, chapterId],
53→        queryFn: () => getChapter(storyId, chapterId, token),
54→        enabled: !!storyId && !!chapterId,
55→        staleTime: 1000 * 60 * 10,
56→        refetchOnWindowFocus: false,
57→    });
58→};
